#include<cstdio>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=5e5+10,BK=256,BB=N/BK+10;
int blk,n,a[N],P[N],p,Q,loc[N],ql[BB],qr[BB],L=0,R=1,c[N],Ans,S[BB][BB]; 
int stk[N],top;inline void Clear(){while(top)c[stk[top--]]=0;}
inline void ins(int x){if((++c[stk[++top]=x])>Ans)Ans=c[x];}
inline int bnd(int k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
int buf[N],m[N],*pos[N],*Tmp=buf,idx[N];
int main()
{
	n=read();Q=read();rep(1,n,i)a[i]=P[i]=read(),loc[i]=(i-1)/BK+1;blk=loc[n];
	std::sort(P+1,P+n+1);p=std::unique(P+1,P+n+1)-P-1;rep(1,n,i)++m[a[i]=bnd(a[i])];
	rep(1,blk,i)ql[i]=qr[i-1]+1,qr[i]=i*BK;qr[blk]=n;rep(1,p,i)pos[i]=Tmp,Tmp+=m[i];
	rep(1,blk,L){Ans=0;int r=ql[L]-1;rep(L,blk,R){while(r<qr[R])ins(a[++r]);S[L][R]=Ans;}Clear();}
	memset(m,0,(p+3)<<2);rep(1,n,i)pos[a[i]][++m[a[i]]]=i,idx[i]=m[a[i]];
	Ans=0;while(Q--)
	{
//		Ans=0;
		int l=read()^Ans,r=read()^Ans,L=loc[l],R=loc[r];
		if(R-L<=1){Ans=0;rep(l,r,i)ins(a[i]);Clear();}
		else
		{
			Ans=S[L+1][R-1];//printf("QAQ :: %d %d %d\n",Ans,L+1,R-1);
			drep(qr[L],l,i)if(idx[i]+Ans<=m[a[i]]&&pos[a[i]][idx[i]+Ans]<ql[R])++Ans;//,printf("QwQ %d %d\n",i,Ans);
			rep(ql[R],r,i) if(idx[i]-Ans>=1      &&pos[a[i]][idx[i]-Ans]>=l)++Ans;//,printf("QwQ %d %d %d\n",i,Ans,idx[i]);
		}
		printf("%d\n",Ans);
	}
	return 0;
}
